export type ReportCategory = 'streetlight' | 'pothole' | 'trashcan' | 'playground' | 'other';
export type HazardLevel = 'low' | 'medium' | 'high';
export type ReportStatus = 'open' | 'resolved';

export interface Report {
  id: string;
  lat: number;
  lng: number;
  address?: string; // New field for human-readable address
  category: ReportCategory;
  categoryLabel: string;
  description: string;
  photoUrl: string | null;
  timestamp: number;
  hazardLevel: HazardLevel;
  status: ReportStatus;
}

export interface NewReportForm {
  lat: number;
  lng: number;
}

import React, { useState, useEffect } from 'react';
import { MapContainer, TileLayer, Marker, Popup, useMapEvents } from 'react-leaflet';
import L from 'leaflet';
import { Plus, X, ChevronRight, Menu, HelpCircle } from 'lucide-react';

import { Report, ReportCategory, HazardLevel } from './types';
import { InstructionBox } from './components/InstructionBox';
import { ReportForm } from './components/ReportForm';
import { SearchField } from './components/SearchField';
import { ReportSidebar } from './components/ReportSidebar';
import { MapController } from './components/MapController';
import { OnboardingModal } from './components/OnboardingModal';

// Fix for default Leaflet icons
delete (L.Icon.Default.prototype as any)._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon-2x.png',
  iconUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon.png',
  shadowUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-shadow.png',
});

// Custom red icon for temp marker
const tempIcon = new L.Icon({
    iconUrl: 'https://raw.githubusercontent.com/pointhi/leaflet-color-markers/master/img/marker-icon-red.png',
    shadowUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/0.7.7/images/marker-shadow.png',
    iconSize: [25, 41],
    iconAnchor: [12, 41],
    popupAnchor: [1, -34],
    shadowSize: [41, 41]
});

// Helper function to fetch address from Coordinates (Reverse Geocoding)
const fetchAddress = async (lat: number, lng: number): Promise<string> => {
  try {
    const response = await fetch(
      `https://nominatim.openstreetmap.org/reverse?format=json&lat=${lat}&lon=${lng}&zoom=18&addressdetails=1`,
      {
        headers: {
          'User-Agent': 'PetaFasilitasPublikApp/1.0' // Good practice for OSM Nominatim
        }
      }
    );
    const data = await response.json();
    if (data && data.address) {
      const road = data.address.road || '';
      const suburb = data.address.suburb || data.address.village || '';
      const city = data.address.city || data.address.town || data.address.regency || '';

      const parts = [road, suburb, city].filter(p => p);
      return parts.join(', ');
    }
    return '';
  } catch (error) {
    console.error("Error fetching address:", error);
    return '';
  }
};

// Map Click Handler Component
const MapEvents = ({ 
  isAddingMode, 
  onMapClick 
}: { 
  isAddingMode: boolean; 
  onMapClick: (lat: number, lng: number) => void; 
}) => {
  useMapEvents({
    click(e) {
      if (isAddingMode) {
        onMapClick(e.latlng.lat, e.latlng.lng);
      }
    },
  });
  return null;
};

// Helper for Hazard Badge in Popup
const getHazardBadge = (level: HazardLevel) => {
  switch(level) {
    case 'high': 
      return <span className="px-2 py-0.5 rounded text-[10px] font-bold bg-red-100 text-red-700 border border-red-200 uppercase tracking-wider">Bahaya Tinggi</span>;
    case 'medium': 
      return <span className="px-2 py-0.5 rounded text-[10px] font-bold bg-yellow-100 text-yellow-700 border border-yellow-200 uppercase tracking-wider">Bahaya Sedang</span>;
    case 'low': 
      return <span className="px-2 py-0.5 rounded text-[10px] font-bold bg-green-100 text-green-700 border border-green-200 uppercase tracking-wider">Bahaya Rendah</span>;
    default: return null;
  }
};

const App: React.FC = () => {
  const [reports, setReports] = useState<Report[]>([]);
  const [tempLocation, setTempLocation] = useState<{ lat: number; lng: number } | null>(null);
  const [isFormOpen, setIsFormOpen] = useState(false);

  // New States
  const [isAddingMode, setIsAddingMode] = useState(false);
  const [flyToPosition, setFlyToPosition] = useState<{ lat: number; lng: number } | null>(null);
  const [isMobileSidebarOpen, setIsMobileSidebarOpen] = useState(false);
  // CHANGED: Initial state set to true (collapsed by default)
  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(true);

  // Onboarding State
  const [showOnboarding, setShowOnboarding] = useState(false);

  useEffect(() => {
    // Check if user has seen onboarding
    const hasSeen = localStorage.getItem('hasSeenOnboarding');
    if (!hasSeen) {
      setShowOnboarding(true);
    }
  }, []);

  const handleCloseOnboarding = () => {
    setShowOnboarding(false);
    localStorage.setItem('hasSeenOnboarding', 'true');
  };

  const handleOpenTutorial = () => {
    setShowOnboarding(true);
  };

  // Initial Indonesia Bounds
  const indonesiaCenter: L.LatLngExpression = [-2.5489, 118.0149];
  const bounds = L.latLngBounds(L.latLng(6.0, 95.0), L.latLng(-11.0, 141.0));

  const handleStartAdding = () => {
    setIsAddingMode(true);
    setFlyToPosition(null); 
    setIsMobileSidebarOpen(false);
  };

  const handleCancelAdding = () => {
    setIsAddingMode(false);
  };

  const handleMapClick = (lat: number, lng: number) => {
    if (!isAddingMode) return;

    setTempLocation({ lat, lng });
    setIsFormOpen(true);
    setIsAddingMode(false);
  };

  const handleCloseForm = () => {
    setIsFormOpen(false);
    setTempLocation(null);
  };

  const handleSubmitReport = async (data: {
    category: ReportCategory;
    categoryLabel: string;
    description: string;
    photoUrl: string | null;
    hazardLevel: HazardLevel;
  }) => {
    if (!tempLocation) return;

    // Create report immediately with coordinate fallback
    const tempId = Date.now().toString();
    const newReport: Report = {
      id: tempId,
      lat: tempLocation.lat,
      lng: tempLocation.lng,
      address: 'Mengambil alamat...', // Placeholder
      ...data,
      timestamp: Date.now(),
      status: 'open', // Default status
    };

    // Optimistic UI update
    setReports((prev) => [newReport, ...prev]);
    setIsFormOpen(false);
    setTempLocation(null);
    setFlyToPosition({ lat: newReport.lat, lng: newReport.lng });

    // Fetch real address
    const address = await fetchAddress(newReport.lat, newReport.lng);

    // Update the report with the real address
    setReports((prev) => prev.map(r => 
      r.id === tempId ? { ...r, address: address || 'Alamat tidak ditemukan' } : r
    ));
  };

  const handleResolveReport = (id: string) => {
    // Mark report as resolved (filtered out from view)
    setReports((prev) => prev.map(r => 
      r.id === id ? { ...r, status: 'resolved' } : r
    ));
  };

  const handleSidebarReportClick = (report: Report) => {
    setFlyToPosition({ lat: report.lat, lng: report.lng });
    setIsMobileSidebarOpen(false);
  };

  // Filter reports to only show "open" issues
  const activeReports = reports.filter(r => r.status === 'open');

  return (
    <div className="h-screen w-full flex overflow-hidden bg-gray-100 font-sans text-gray-800">

      {showOnboarding && <OnboardingModal onClose={handleCloseOnboarding} />}

      {/* Sidebar Container */}
      <div className={`
        fixed inset-0 z-[2000] 
        md:z-auto md:relative md:flex 
        transition-all duration-500 ease-in-out
        ${isMobileSidebarOpen ? 'translate-x-0' : '-translate-x-full'}
        ${isSidebarCollapsed ? 'md:w-0 md:-translate-x-full md:opacity-0 md:overflow-hidden' : 'md:w-[420px] md:translate-x-0 md:opacity-100'}
      `}>
        <ReportSidebar 
          reports={activeReports} 
          onReportClick={handleSidebarReportClick} 
          onCollapse={() => setIsSidebarCollapsed(true)}
          onResolve={handleResolveReport}
        />
        {/* Mobile Sidebar Close Button */}
        <button 
          className="absolute top-4 right-4 md:hidden p-2 bg-white rounded-full shadow-lg text-gray-600"
          onClick={() => setIsMobileSidebarOpen(false)}
        >
          <X size={20} />
        </button>
      </div>

      {/* Main Map Area */}
      <div className="flex-1 relative h-full">

        {/* Mobile Toggle Button */}
        {!isMobileSidebarOpen && !isAddingMode && (
           <button 
             className="md:hidden absolute top-4 left-4 z-[1000] bg-white px-4 py-2 rounded-lg shadow-md text-gray-700 font-semibold text-xs flex items-center"
             onClick={() => setIsMobileSidebarOpen(true)}
           >
             <Menu size={16} className="mr-2" />
             Daftar
           </button>
        )}

        {/* Desktop Re-open Button (Visible when sidebar is collapsed) */}
        {isSidebarCollapsed && (
          <button
            onClick={() => setIsSidebarCollapsed(false)}
            className="hidden md:flex absolute top-1/2 left-0 -translate-y-1/2 z-[1000] bg-white hover:bg-gray-50 text-gray-700 p-3 rounded-r-xl shadow-lg border-y border-r border-gray-200 transition-all hover:w-12 w-10 group justify-center"
            title="Tampilkan Sidebar"
          >
            <ChevronRight size={24} className="group-hover:text-blue-600 transition-colors" />
          </button>
        )}

        <MapContainer 
          center={indonesiaCenter} 
          zoom={5} 
          minZoom={4}
          maxBounds={bounds}
          maxBoundsViscosity={1.0}
          scrollWheelZoom={true}
          className={`h-full w-full z-0 transition-cursor duration-200 ${isAddingMode ? 'cursor-crosshair' : ''}`}
        >
          <TileLayer
            attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a>'
            url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
          />

          <SearchField />
          <MapController targetLocation={flyToPosition} />
          <MapEvents isAddingMode={isAddingMode} onMapClick={handleMapClick} />

          {/* Saved Reports Markers */}
          {activeReports.map((report) => (
            <Marker key={report.id} position={[report.lat, report.lng]}>
              <Popup className="custom-popup" autoPan={true}>
                <div className="min-w-[200px] max-w-[250px]">
                  <div className="mb-2 flex justify-between items-center gap-2">
                    <span className="inline-block px-2 py-0.5 rounded text-xs font-bold bg-blue-100 text-blue-800">
                      {report.categoryLabel}
                    </span>
                    {getHazardBadge(report.hazardLevel)}
                  </div>
                  <h3 className="font-semibold text-gray-800 mb-1">{report.address || 'Memuat lokasi...'}</h3>
                  <p className="text-gray-600 text-sm mb-2">{report.description}</p>
                  {report.photoUrl && (
                    <img 
                      src={report.photoUrl} 
                      alt="Laporan" 
                      className="w-full h-32 object-cover rounded-md border border-gray-200" 
                    />
                  )}

                  {/* Action in Popup */}
                  <div className="mt-3 pt-3 border-t border-gray-100 flex justify-between items-center">
                    <span className="text-xs text-gray-400">
                      {new Date(report.timestamp).toLocaleDateString()}
                    </span>
                    <button 
                      onClick={(e) => {
                        // Leaflet popup event handling can be tricky, using sidebar is safer but adding here for completeness
                        handleResolveReport(report.id);
                      }}
                      className="text-xs bg-green-500 hover:bg-green-600 text-white px-2 py-1 rounded transition-colors"
                    >
                      Selesai
                    </button>
                  </div>
                </div>
              </Popup>
            </Marker>
          ))}

          {tempLocation && (
            <Marker position={[tempLocation.lat, tempLocation.lng]} icon={tempIcon} />
          )}
        </MapContainer>

        <InstructionBox visible={true} mode={isAddingMode ? 'add' : 'view'} />

        {/* Floating Help Button (Bottom Left) */}
        {!isAddingMode && (
          <button
            onClick={handleOpenTutorial}
            className="absolute bottom-6 left-6 z-[1000] bg-white text-gray-600 hover:text-blue-600 p-3 rounded-full shadow-lg border border-gray-200 transition-all hover:scale-110 active:scale-95 group"
            title="Buka Tutorial"
          >
            <HelpCircle size={24} />
            <span className="absolute left-full ml-3 top-1/2 -translate-y-1/2 px-2 py-1 bg-gray-800 text-white text-xs rounded opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap pointer-events-none">
              Bantuan
            </span>
          </button>
        )}

        {/* Floating Action Button (Bottom Right) */}
        <div className="absolute bottom-8 right-6 z-[1000] flex flex-col items-end space-y-3">
          {isAddingMode ? (
             <button
              onClick={handleCancelAdding}
              className="bg-red-500 hover:bg-red-600 text-white px-6 py-3 rounded-full shadow-lg font-semibold flex items-center transition-all animate-fade-in-up"
            >
              <X size={20} className="mr-2" />
              Batal
            </button>
          ) : (
            <button
              onClick={handleStartAdding}
              className="group bg-gradient-to-tr from-blue-600 to-indigo-600 hover:from-blue-700 hover:to-indigo-700 text-white w-16 h-16 rounded-full shadow-xl shadow-blue-600/30 flex items-center justify-center transition-all hover:scale-110 active:scale-95 border-4 border-white/20"
              title="Buat Laporan Baru"
            >
              <Plus size={32} />
            </button>
          )}
        </div>

        {isFormOpen && tempLocation && (
          <ReportForm 
            lat={tempLocation.lat} 
            lng={tempLocation.lng} 
            onClose={handleCloseForm}
            onSubmit={handleSubmitReport}
          />
        )}
      </div>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Report, ReportCategory, HazardLevel } from '../types';
import { Search, MapPin, Calendar, Image as ImageIcon, AlertTriangle, Lightbulb, Trash2, Palmtree, HelpCircle, ChevronLeft, AlertCircle, CheckCircle2, Filter, Info, Check } from 'lucide-react';

interface ReportSidebarProps {
  reports: Report[];
  onReportClick: (report: Report) => void;
  onCollapse: () => void;
  onResolve: (id: string) => void;
}

const getCategoryStyles = (category: ReportCategory) => {
  switch (category) {
    case 'pothole':
      return { bg: 'bg-red-50', text: 'text-red-700', border: 'border-red-200', icon: AlertTriangle };
    case 'streetlight':
      return { bg: 'bg-yellow-50', text: 'text-yellow-700', border: 'border-yellow-200', icon: Lightbulb };
    case 'trashcan':
      return { bg: 'bg-green-50', text: 'text-green-700', border: 'border-green-200', icon: Trash2 };
    case 'playground':
      return { bg: 'bg-purple-50', text: 'text-purple-700', border: 'border-purple-200', icon: Palmtree };
    default:
      return { bg: 'bg-gray-50', text: 'text-gray-700', border: 'border-gray-200', icon: HelpCircle };
  }
};

const getHazardInfo = (level: HazardLevel) => {
  switch (level) {
    case 'high':
      return { bg: 'bg-red-100', text: 'text-red-700', label: 'Tinggi', icon: AlertCircle, color: 'red' };
    case 'medium':
      return { bg: 'bg-yellow-100', text: 'text-yellow-700', label: 'Sedang', icon: AlertTriangle, color: 'yellow' };
    case 'low':
      return { bg: 'bg-green-100', text: 'text-green-700', label: 'Rendah', icon: CheckCircle2, color: 'green' };
  }
};

