            <Filter size={12} className="mr-1.5" /> Semua
          </button>
          <button onClick={() => setHazardFilter('high')} className={`px-3 py-1.5 rounded-lg text-xs font-semibold transition-all border whitespace-nowrap flex items-center ${hazardFilter === 'high' ? 'bg-red-500 text-white border-red-400 shadow-md' : 'bg-blue-800/50 text-blue-100 border-transparent hover:bg-red-900/50'}`}>
            <AlertCircle size={12} className="mr-1.5" /> Tinggi
          </button>
          <button onClick={() => setHazardFilter('medium')} className={`px-3 py-1.5 rounded-lg text-xs font-semibold transition-all border whitespace-nowrap flex items-center ${hazardFilter === 'medium' ? 'bg-yellow-400 text-yellow-900 border-yellow-300 shadow-md' : 'bg-blue-800/50 text-blue-100 border-transparent hover:bg-yellow-900/50'}`}>
            <AlertTriangle size={12} className="mr-1.5" /> Sedang
