// Helper function to fetch address from Coordinates (Reverse Geocoding)
const fetchAddress = async (lat: number, lng: number): Promise<string> => {
  try {
    const response = await fetch(
      `https://nominatim.openstreetmap.org/reverse?format=json&lat=${lat}&lon=${lng}&zoom=18&addressdetails=1`
    );

    if (!response.ok) {
      throw new Error(`HTTP error! status: ${response.status}`);
    }

    const data = await response.json();
    if (data && data.address) {
      const road = data.address.road || '';
      const suburb = data.address.suburb || data.address.village || '';
      const city = data.address.city || data.address.town || data.address.regency || '';

      const parts = [road, suburb, city].filter(p => p);
      return parts.join(', ');
    }
    return '';
  } catch (error) {
    console.error("Error fetching address:", error);
    return '';
  }
};

