                    <span className="text-[10px] text-gray-400 font-medium">
                      Dilaporkan pada: {new Date(report.timestamp).toLocaleDateString('id-ID', { day: 'numeric', month: 'long', year: 'numeric' })}
                    </span>
                  </div>
                </div>
              </Popup>
            </Marker>
          ))}

          {tempLocation && (
            <Marker 
              position={[tempLocation.lat, tempLocation.lng]} 
