              {isPlusHovered && (
                <div className="absolute bottom-[110%] right-0 mb-2 animate-fade-in-up">
                  <div className="relative bg-blue-100/90 backdrop-blur-md border border-blue-200 px-4 py-2.5 rounded-2xl shadow-xl whitespace-nowrap flex flex-col items-center">
                    <span className="text-blue-800 text-xs font-bold leading-tight">
                      Tekan tombol + untuk melapor
                    </span>
                    {/* Tooltip Arrow */}
                    <div className="absolute -bottom-1.5 right-6 w-3 h-3 bg-blue-100 border-r border-b border-blue-200 transform rotate-45"></div>
                  </div>
                </div>
              )}

              <button
                onMouseEnter={() => setIsPlusHovered(true)}
                onMouseLeave={() => setIsPlusHovered(false)}
                onClick={handleStartAdding}
                className="group bg-gradient-to-tr from-blue-600 to-indigo-600 hover:from-blue-700 hover:to-indigo-700 text-white w-16 h-16 rounded-full shadow-xl shadow-blue-600/30 flex items-center justify-center transition-all hover:scale-110 active:scale-95 border-4 border-white/20"
                aria-label="Buat Laporan Baru"
              >
                <Plus size={32} />
              </button>
            </div>
          )}
        </div>

        {isFormOpen && tempLocation && (
          <ReportForm 
            lat={tempLocation.lat} 
            lng={tempLocation.lng} 
            onClose={handleCloseForm}
            onSubmit={handleSubmitReport}
          />
        )}
      </div>
    </div>
  );
};

