          <button 
            onClick={() => setIsSidebarCollapsed(true)}
            className="hidden md:flex absolute left-full top-1/2 -translate-y-1/2 z-[2001] bg-white hover:bg-gray-50 text-blue-950 p-0 rounded-r-xl shadow-xl border border-blue-950 transition-all hover:w-11 w-9 h-14 min-w-[36px] items-center justify-center group"
            title="Sembunyikan Sidebar"
          >
            <ChevronLeft size={24} strokeWidth={2.5} className="group-hover:-translate-x-0.5 transition-transform" />
          </button>
        )}

        <button 
          className="absolute top-4 right-4 md:hidden p-2 bg-white rounded-full shadow-lg text-gray-600"
          onClick={() => setIsMobileSidebarOpen(false)}
        >
          <X size={20} />
        </button>
      </div>

      <div className="flex-1 relative h-full">
        {!isMobileSidebarOpen && !isAddingMode && (
           <button 
             className="md:hidden absolute top-4 left-4 z-[1000] bg-white px-4 py-2 rounded-lg shadow-md text-gray-700 font-semibold text-xs flex items-center"
             onClick={() => setIsMobileSidebarOpen(true)}
           >
             <Menu size={16} className="mr-2" />
             Daftar
           </button>
        )}

        {/* Open Button: Visible when sidebar is collapsed */}
        {isSidebarCollapsed && (
          <button
            onClick={() => setIsSidebarCollapsed(false)}
            className="hidden md:flex absolute top-1/2 left-0 -translate-y-1/2 z-[1000] bg-white hover:bg-gray-50 text-blue-950 p-0 rounded-r-xl shadow-xl border border-blue-950 transition-all hover:w-11 w-9 h-14 min-w-[36px] group justify-center items-center overflow-hidden"
