// Helper function to fetch address from Coordinates (Reverse Geocoding)
const fetchAddress = async (lat: number, lng: number): Promise<string> => {
  try {
    const response = await fetch(
      `https://nominatim.openstreetmap.org/reverse?format=json&lat=${lat}&lon=${lng}&zoom=18&addressdetails=1`
    );

    if (!response.ok) {
      throw new Error(`HTTP error! status: ${response.status}`);
    }

    const data = await response.json();
    if (data && data.address) {
      const road = data.address.road || '';
      const suburb = data.address.suburb || data.address.village || '';
      const city = data.address.city || data.address.town || data.address.regency || '';

      const parts = [road, suburb, city].filter(p => p);
      return parts.join(', ');
    }
    return '';
  } catch (error) {
    console.error("Error fetching address:", error);
    return '';
  }
};

// Map Click Handler Component
const MapEvents = ({ 
  isAddingMode, 
  onMapClick 
}: { 
  isAddingMode: boolean; 
  onMapClick: (lat: number, lng: number) => void; 
}) => {
  useMapEvents({
    click(e) {
      if (isAddingMode) {
        onMapClick(e.latlng.lat, e.latlng.lng);
      }
    },
  });
  return null;
};

// Helper for Hazard Badge in Popup
const getHazardBadge = (level: HazardLevel) => {
  switch(level) {
    case 'high': 
      return <span className="px-2 py-0.5 rounded text-[10px] font-bold bg-red-100 text-red-700 border border-red-200 uppercase tracking-wider">Bahaya Tinggi</span>;
    case 'medium': 
      return <span className="px-2 py-0.5 rounded text-[10px] font-bold bg-yellow-100 text-yellow-700 border border-yellow-200 uppercase tracking-wider">Bahaya Sedang</span>;
    case 'low': 
      return <span className="px-2 py-0.5 rounded text-[10px] font-bold bg-green-100 text-green-700 border border-green-200 uppercase tracking-wider">Bahaya Rendah</span>;
    default: return null;
  }
};

const App: React.FC = () => {
  const [reports, setReports] = useState<Report[]>([]);
  const [tempLocation, setTempLocation] = useState<{ lat: number; lng: number } | null>(null);
  const [isFormOpen, setIsFormOpen] = useState(false);

  const [isAddingMode, setIsAddingMode] = useState(false);
  const [flyToPosition, setFlyToPosition] = useState<{ lat: number; lng: number } | null>(null);
  const [isMobileSidebarOpen, setIsMobileSidebarOpen] = useState(false);
  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(true);
  const [showOnboarding, setShowOnboarding] = useState(false);
  const [isPlusHovered, setIsPlusHovered] = useState(false);

