        >
          <X size={20} />
        </button>
      </div>

      <div className="flex-1 relative h-full">
        {/* Unified Sidebar Toggle Button for Desktop */}
        <button
          onClick={() => setIsSidebarCollapsed(!isSidebarCollapsed)}
          className={`hidden md:flex fixed top-1/2 -translate-y-1/2 z-[3000] bg-white hover:bg-gray-50 text-blue-950 p-0 rounded-r-xl shadow-xl border border-blue-950 transition-all duration-500 ease-in-out w-9 h-14 items-center justify-center group overflow-hidden`}
          style={{ left: isSidebarCollapsed ? '0px' : '420px' }}
          title={isSidebarCollapsed ? "Tampilkan Sidebar" : "Sembunyikan Sidebar"}
        >
          {isSidebarCollapsed ? (
            <ChevronRight size={24} strokeWidth={2.5} className="group-hover:translate-x-0.5 transition-transform" />
          ) : (
            <ChevronLeft size={24} strokeWidth={2.5} className="group-hover:-translate-x-0.5 transition-transform" />
