              >
                {photoUrl ? (
                  <img src={photoUrl} alt="Preview" className="w-full h-full object-cover" />
                ) : (
                  <>
                    <Upload size={24} className="text-gray-400 mb-2 group-hover:text-blue-500 transition-colors" />
                    <span className="text-xs text-gray-500 font-medium">Ambil Foto / Upload</span>
                  </>
                )}
              </div>
              <input 
                type="file" 
                ref={fileInputRef} 
                onChange={handleFileChange} 
                accept="image/*" 
                className="hidden" 
              />
            </div>

            <button 
              type="submit" 
              className="w-full bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-700 hover:to-indigo-700 text-white font-bold py-3.5 rounded-xl shadow-lg shadow-blue-500/30 transition-all transform active:scale-95 mt-2"
            >
              Kirim Laporan
            </button>
          </div>
        )}
      </form>
    </div>
  );
};

