    setReports((prev) => prev.map(r => {
      if (r.id === id) {
        const currentIndex = statusCycle.indexOf(r.status);
        const nextIndex = (currentIndex + 1) % statusCycle.length;
        const newStatus = statusCycle[nextIndex];

        // Simulasikan penambahan "Impact Metric" jika resolved
        const updates: Partial<Report> = { status: newStatus };
        if (newStatus === 'resolved' && !r.impactMetric) {
           updates.impactMetric = "Masalah terselesaikan dalam 3 hari";
        }

        return { ...r, ...updates };
      }
      return r;
    }));
  };

  // Share Logic (Simulation)
  const handleShareReport = (report: Report) => {
    const dummyLink = `https://lapor-fasilitas.id/report/${report.id}`;
    if (navigator.share) {
      navigator.share({
        title: `Laporan: ${report.categoryLabel}`,
        text: `Bantu verifikasi laporan ini: ${report.description}`,
        url: dummyLink,
      }).catch(console.error);
    } else {
      navigator.clipboard.writeText(dummyLink);
      alert(`Link disalin: ${dummyLink}`);
    }
  };

  const handleSidebarReportClick = (report: Report) => {
    setFlyToPosition({ lat: report.lat, lng: report.lng });
  };

  return (
    <div className="h-screen w-full flex overflow-hidden bg-gray-100 font-sans text-gray-800">
      {showOnboarding && <OnboardingModal onClose={handleCloseOnboarding} />}

      {/* Unified Sidebar Toggle Button for Desktop */}
      {/* UPDATE: Z-Index lowered to 1000 to sit below modals (3000) but above map (0) */}
      <button
        onClick={() => setIsSidebarCollapsed(!isSidebarCollapsed)}
        className="hidden md:flex absolute top-1/2 -translate-y-1/2 z-[1000] bg-white hover:bg-gray-50 text-blue-950 p-0 rounded-r-xl shadow-xl border border-blue-950 transition-all duration-500 ease-in-out w-9 h-14 min-w-[36px] items-center justify-center group"
        style={{ left: isSidebarCollapsed ? '0px' : '420px' }}
        title={isSidebarCollapsed ? "Tampilkan Sidebar" : "Sembunyikan Sidebar"}
      >
        {isSidebarCollapsed ? (
          <ChevronRight size={24} strokeWidth={2.5} className="group-hover:translate-x-0.5 transition-transform" />
        ) : (
          <ChevronLeft size={24} strokeWidth={2.5} className="group-hover:-translate-x-0.5 transition-transform" />
        )}
      </button>

      {/* Sidebar Container */}
      <div className={`
        fixed inset-0 z-[2000] pointer-events-none
        md:z-auto md:relative md:flex md:pointer-events-auto
        transition-all duration-500 ease-in-out md:overflow-visible
        ${isSidebarCollapsed ? 'md:w-0 md:opacity-0 md:-translate-x-full' : 'md:w-[420px] md:opacity-100 md:translate-x-0'}
      `}>
        {/* Pointer events enabled only for the sidebar content itself on mobile */}
        <div className="w-full h-full pointer-events-auto">
           <ReportSidebar 
            reports={reports} 
            onReportClick={handleSidebarReportClick} 
            onVerify={handleVerifyReport}
            onShare={handleShareReport}
            onStatusChange={handleStatusChange}
          />
        </div>
      </div>

      <div className="flex-1 relative h-full">
        <MapContainer 
          center={indonesiaCenter} 
          zoom={5} 
          minZoom={4}
          maxBounds={bounds}
          maxBoundsViscosity={1.0}
          scrollWheelZoom={true}
          className={`h-full w-full z-0 transition-cursor duration-200 ${isAddingMode ? 'cursor-crosshair' : ''}`}
        >
          <TileLayer
            attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a>'
            url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
          />

          <SearchField />
          <MapController targetLocation={flyToPosition} />
          <MapEvents isAddingMode={isAddingMode} onMapClick={handleMapClick} />

          {reports.map((report) => (
            <Marker key={report.id} position={[report.lat, report.lng]} icon={icons[report.status] || icons.reported}>
              <Popup className="custom-popup" autoPan={true}>
                <div className="min-w-[200px] max-w-[250px]">
                  <div className="mb-2 flex justify-between items-center gap-2">
                    <span className="inline-block px-2 py-0.5 rounded text-xs font-bold bg-blue-100 text-blue-800">
                      {report.categoryLabel}
                    </span>
                  </div>
                  <h3 className="font-semibold text-gray-800 mb-1 leading-tight">{report.address || 'Memuat lokasi...'}</h3>
                  <p className="text-gray-600 text-sm mb-2">{report.description}</p>
                  {report.photoUrl && (
                    <img src={report.photoUrl} alt="Laporan" className="w-full h-32 object-cover rounded-md border border-gray-200 mb-2" />
                  )}
                  <div className="flex justify-between items-center mt-2 pt-2 border-t border-gray-100">
                     <span className="text-[10px] text-gray-400">
                       {new Date(report.timestamp).toLocaleDateString('id-ID')}
                     </span>
                     <span className="text-xs font-bold text-blue-600 flex items-center">
                       <Plus size={10} className="mr-0.5" /> {report.upvotes} Verifikasi
                     </span>
                  </div>
                </div>
              </Popup>
            </Marker>
          ))}

          {tempLocation && (
            <Marker position={[tempLocation.lat, tempLocation.lng]} icon={icons.temp} draggable={true} />
          )}
        </MapContainer>

        <InstructionBox visible={true} mode={isAddingMode ? 'add' : 'view'} />

        {/* Help Button - Moved to Bottom Left, Fixed position to be covered by Sidebar */}
        {!isAddingMode && (
          <div className="fixed bottom-8 left-6 z-[1000] hidden md:block">
            <button
              onClick={() => setShowOnboarding(true)}
