import React, { useState } from 'react';
import { Report, HazardLevel, ReportStatus } from '../types';
import { Search, MapPin, Calendar, Image as ImageIcon, Share2, ThumbsUp, Clock, Activity, CheckCircle2, Filter, Info, ChevronUp, ChevronDown } from 'lucide-react';

interface ReportSidebarProps {
  reports: Report[];
  onReportClick: (report: Report) => void;
  onVerify: (id: string) => void;
  onShare: (report: Report) => void;
  onStatusChange?: (id: string) => void; // New prop for simulation
}

// Visualisasi Status (Pizza Tracker)
const getStatusConfig = (status: ReportStatus) => {
  switch (status) {
    case 'reported':
      return { label: 'Dilaporkan', color: 'bg-gray-100 text-gray-600', dot: 'bg-gray-400', icon: Clock };
    case 'reviewed':
      return { label: 'Ditinjau', color: 'bg-blue-100 text-blue-700', dot: 'bg-blue-500', icon: Activity };
    case 'in_progress':
      return { label: 'Dikerjakan', color: 'bg-orange-100 text-orange-700', dot: 'bg-orange-500', icon: Activity };
    case 'resolved':
      return { label: 'Selesai', color: 'bg-green-100 text-green-700', dot: 'bg-green-500', icon: CheckCircle2 };
  }
};

const getHazardInfo = (level: HazardLevel) => {
  switch (level) {
    case 'high': return { bg: 'bg-red-500', text: 'text-white', label: 'Darurat' };
    case 'medium': return { bg: 'bg-yellow-400', text: 'text-yellow-900', label: 'Sedang' };
    case 'low': return { bg: 'bg-green-500', text: 'text-white', label: 'Rendah' };
  }
};

export const ReportSidebar: React.FC<ReportSidebarProps> = ({ reports, onReportClick, onVerify, onShare, onStatusChange }) => {
  const [searchQuery, setSearchQuery] = useState('');
  const [hazardFilter, setHazardFilter] = useState<HazardLevel | 'all'>('all');
  const [isMobileExpanded, setIsMobileExpanded] = useState(false); // Untuk bottom sheet

  const filteredReports = reports.filter((report) => {
    const matchesSearch = 
      report.description.toLowerCase().includes(searchQuery.toLowerCase()) ||
      report.categoryLabel.toLowerCase().includes(searchQuery.toLowerCase()) ||
      (report.address || '').toLowerCase().includes(searchQuery.toLowerCase());

    const matchesHazard = hazardFilter === 'all' || report.hazardLevel === hazardFilter;

    return matchesSearch && matchesHazard;
  });

  return (
    <div className={`
      absolute md:relative z-[1001] bg-white shadow-2xl flex flex-col border-blue-950/20 md:border-r transition-all duration-300
      /* Mobile Styles (Bottom Sheet) */
      bottom-0 left-0 w-full rounded-t-3xl md:rounded-none
      ${isMobileExpanded ? 'h-[85vh]' : 'h-[35vh]'} 
      /* Desktop Styles */
      md:h-full md:w-[420px] md:top-0 md:bottom-auto
    `}>

      {/* Mobile Drag Handle / Toggle */}
      <div 
        className="md:hidden w-full flex justify-center pt-3 pb-1 cursor-pointer bg-gradient-to-r from-blue-600 to-indigo-600 rounded-t-3xl"
        onClick={() => setIsMobileExpanded(!isMobileExpanded)}
      >
        <div className="w-12 h-1.5 bg-white/30 rounded-full mb-1"></div>
      </div>

      {/* UPDATE: Header background changed to blue gradient, Text to white */}
      <div className="px-6 pb-6 pt-4 md:pt-6 bg-gradient-to-r from-blue-600 to-indigo-600 z-10 sticky top-0 md:relative shadow-md">
        <h1 className="text-xl md:text-2xl font-bold mb-1 tracking-tight text-white">Laporan Warga</h1>
        <p className="text-blue-100 text-xs mb-3 opacity-90">Pantau fasilitas publik di sekitarmu</p>

        {/* Search Bar - Adjusted for blue background */}
        <div className="relative group mb-4">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-blue-200 group-focus-within:text-blue-500 transition-colors" size={16} />
          <input
            type="text"
            placeholder="Cari jalan atau masalah..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="w-full pl-9 pr-4 py-2.5 bg-blue-900/30 border border-blue-400/30 text-white placeholder-blue-200/70 rounded-xl focus:outline-none focus:bg-white focus:text-gray-900 focus:placeholder-gray-400 focus:ring-2 focus:ring-blue-300 transition-all text-sm backdrop-blur-sm"
          />
        </div>

        {/* Filters - Adjusted for blue background */}
        <div className="flex gap-2 overflow-x-auto pb-1 scrollbar-hide">
          {['all', 'high', 'medium', 'low'].map((filter) => (
            <button 
              key={filter}
              onClick={() => setHazardFilter(filter as any)}
              className={`px-3 py-1.5 rounded-full text-xs font-bold whitespace-nowrap border transition-all ${
                hazardFilter === filter 
                  ? 'bg-white text-blue-700 border-white shadow-lg' 
                  : 'bg-blue-800/40 text-blue-100 border-transparent hover:bg-blue-700/50'
              }`}
            >
              {filter === 'all' ? 'Semua' : filter === 'high' ? 'Darurat' : filter === 'medium' ? 'Sedang' : 'Rendah'}
            </button>
          ))}
        </div>
      </div>

      {/* List Content */}
      <div className="flex-1 overflow-y-auto bg-gray-50 p-4 space-y-4">
        {filteredReports.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-48 text-gray-400">
            <p className="font-medium text-sm">Belum ada laporan</p>
          </div>
        ) : (
          filteredReports.map((report) => {
            const statusInfo = getStatusConfig(report.status);
            const hazardInfo = getHazardInfo(report.hazardLevel);

            return (
              <div
                key={report.id}
                onClick={() => onReportClick(report)}
                className="bg-white rounded-2xl p-4 shadow-sm border border-gray-100 hover:shadow-md transition-all cursor-pointer group hover:-translate-y-0.5 duration-200"
              >
                {/* Header: Category & Status Badge */}
                <div className="flex justify-between items-start mb-3">
                  <div>
                    <h3 className="font-bold text-gray-800 text-sm leading-snug">{report.categoryLabel}</h3>
                    <div className="text-xs text-gray-500 flex items-center mt-1">
                       <MapPin size={12} className="mr-1 text-gray-400" />
                       <span className="truncate max-w-[180px]">{report.address || `${report.lat.toFixed(4)}, ${report.lng.toFixed(4)}`}</span>
                    </div>
                  </div>
                  <div className={`px-2 py-1 rounded-md text-[10px] font-bold tracking-wide uppercase ${hazardInfo.bg} ${hazardInfo.text}`}>
                    {hazardInfo.label}
                  </div>
                </div>

                {/* Progress Tracker (Pizza Tracker Lite) - CLICKABLE FOR SIMULATION */}
                <div 
                  className="flex items-center gap-2 mb-3 bg-gray-50 p-2 rounded-lg border border-gray-100 cursor-pointer hover:bg-gray-100 transition-colors"
                  onClick={(e) => {
                    e.stopPropagation();
                    if (onStatusChange) onStatusChange(report.id);
                  }}
                  title="Klik untuk simulasi perubahan status (Admin Mode)"
                >
                   <div className={`w-2 h-2 rounded-full ${statusInfo.dot}`}></div>
                   <span className={`text-xs font-bold ${statusInfo.color.split(' ')[1]}`}>
                     Status: {statusInfo.label}
                   </span>
                   {report.status === 'resolved' && report.impactMetric && (
                     <span className="text-[10px] text-gray-400 ml-auto border-l border-gray-300 pl-2">
                       {report.impactMetric}
                     </span>
                   )}
                </div>

                {/* Description & Photo */}
                <p className="text-sm text-gray-600 mb-3 line-clamp-2 leading-relaxed">{report.description}</p>

                {/* "Before & After" Mockup (Only for resolved) */}
                {report.status === 'resolved' && report.photoUrl && (
                  <div className="flex gap-1 mb-3 h-20 overflow-hidden rounded-lg relative">
                    <div className="w-1/2 relative">
                      <img src={report.photoUrl} className="w-full h-full object-cover grayscale-[50%]" alt="Before" />
                      <span className="absolute bottom-1 left-1 bg-black/60 text-white text-[9px] px-1 rounded">Sebelum</span>
                    </div>
                    {/* Mock After Image (Just blurring/tinting the original for demo) */}
                    <div className="w-1/2 relative">
                      <div className="w-full h-full bg-green-100 flex items-center justify-center text-green-600">
                        <CheckCircle2 size={24} />
                      </div>
                      <span className="absolute bottom-1 right-1 bg-green-600 text-white text-[9px] px-1 rounded">Sesudah</span>
                    </div>
                  </div>
                )}

                {/* Action Buttons (The "Job to be Done" triggers) */}
                <div className="flex items-center justify-between pt-3 border-t border-gray-100">
                  <div className="flex items-center gap-3">
                     <button 
                       onClick={(e) => { e.stopPropagation(); onVerify(report.id); }}
                       className={`flex items-center gap-1.5 text-xs font-semibold px-3 py-1.5 rounded-full transition-colors ${report.isVerifiedByCurrentUser ? 'bg-blue-100 text-blue-700' : 'bg-gray-100 text-gray-600 hover:bg-gray-200'}`}
                     >
                       <ThumbsUp size={14} className={report.isVerifiedByCurrentUser ? 'fill-blue-700' : ''} />
                       {report.upvotes} <span className="hidden sm:inline">Verifikasi</span>
                     </button>
                  </div>

                  <button 
                    onClick={(e) => { e.stopPropagation(); onShare(report); }}
                    className="p-2 text-gray-400 hover:text-blue-600 hover:bg-blue-50 rounded-full transition-all"
                    title="Bagikan Laporan"
                  >
                    <Share2 size={16} />
                  </button>
                </div>
              </div>
            );
          })
        )}
      </div>
    </div>
  );
};

