                className="group bg-gradient-to-tr from-blue-600 to-indigo-600 hover:from-blue-700 hover:to-indigo-700 text-white w-14 h-14 md:w-16 md:h-16 rounded-2xl shadow-xl shadow-blue-600/30 flex items-center justify-center transition-all hover:scale-110 active:scale-95 ring-4 ring-blue-400/30"
                aria-label="Buat Laporan Baru"
              >
                <Plus size={32} />
