        className="hidden md:flex absolute top-1/2 -translate-y-1/2 z-[1000] bg-white hover:bg-gray-50 text-blue-600 p-0 rounded-r-xl shadow-xl border border-gray-200 transition-all duration-500 ease-in-out w-9 h-14 min-w-[36px] items-center justify-center group"
        style={{ left: isSidebarCollapsed ? '0px' : '420px' }}
      >
        {isSidebarCollapsed ? (
          <ChevronRight size={24} strokeWidth={2.5} className="group-hover:translate-x-0.5 transition-transform" />
        ) : (
          <ChevronLeft size={24} strokeWidth={2.5} className="group-hover:-translate-x-0.5 transition-transform" />
        )}
      </button>

      <div className={`
        fixed inset-0 z-[2000] pointer-events-none
        md:relative md:inset-auto md:flex md:z-[2000]
        transition-all duration-500 ease-in-out md:overflow-visible
